import{_ as a,c as e,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"帳號遷移: 備份/熱遷移 | Antigravity Manager","description":"學習 Antigravity Manager 的帳號備份與遷移。支援 JSON 匯入匯出、從 Antigravity/IDE 熱遷移、從 V1 資料目錄遷移，並自動同步目前登入帳號。","frontmatter":{"title":"帳號遷移: 備份/熱遷移 | Antigravity Manager","sidebarTitle":"3 分鐘遷移帳號池","subtitle":"帳號遷移: 備份/熱遷移","description":"學習 Antigravity Manager 的帳號備份與遷移。支援 JSON 匯入匯出、從 Antigravity/IDE 熱遷移、從 V1 資料目錄遷移，並自動同步目前登入帳號。","tags":["帳號管理","備份","遷移","匯入匯出","state.vscdb"],"prerequisite":["start-add-account","start-first-run-data"],"duration":12,"order":5},"headers":[],"relativePath":"zh-tw/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md","filePath":"zh-tw/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"}'),r={name:"zh-tw/lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"};function o(n,t,l,d,c,h){return s(),e("div",null,[...t[0]||(t[0]=[i(`<h1 id="帳號備份與遷移-匯入-匯出、v1-db-熱遷移" tabindex="-1">帳號備份與遷移：匯入/匯出、V1/DB 熱遷移 <a class="header-anchor" href="#帳號備份與遷移-匯入-匯出、v1-db-熱遷移" aria-label="Permalink to &quot;帳號備份與遷移：匯入/匯出、V1/DB 熱遷移&quot;">​</a></h1><p>你真正想「備份」的，其實不是配額數字，而是能讓帳號重新登入的 <code>refresh_token</code>。這節課把 Antigravity Tools 的幾種遷移手段講清楚：匯入/匯出 JSON、從 <code>state.vscdb</code> 匯入、從 V1 資料目錄匯入，以及自動同步的工作方式。</p><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>把帳號池匯出成一個 JSON 檔案（只包含 email + refresh_token）</li><li>在新機器上匯入這個 JSON，快速恢復帳號池</li><li>直接從 Antigravity/IDE 的 <code>state.vscdb</code> 匯入「目前登入帳號」（支援預設路徑與自訂路徑）</li><li>從 V1 資料目錄自動掃描並匯入舊帳號</li><li>了解「自動同步目前帳號」到底會做什麼、什麼時候會跳過</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><ul><li>重裝系統/換電腦後，帳號池要重新加一遍，成本很高</li><li>你在 Antigravity/IDE 裡換了登入帳號，但 Manager 裡的「目前帳號」沒跟著變</li><li>你以前用過 V1/腳本版，手裡只有舊資料檔案，不知道能不能直接遷移</li></ul><h2 id="什麼時候用這一招" tabindex="-1">什麼時候用這一招 <a class="header-anchor" href="#什麼時候用這一招" aria-label="Permalink to &quot;什麼時候用這一招&quot;">​</a></h2><ul><li>你要把帳號池搬到另一台機器（桌面端/伺服器/容器）</li><li>你把 Antigravity 作為「權威登入入口」，希望 Manager 自動同步目前帳號</li><li>你要從舊版本（V1 資料目錄）把帳號遷過來</li></ul><h2 id="🎒-開始前的準備" tabindex="-1">🎒 開始前的準備 <a class="header-anchor" href="#🎒-開始前的準備" aria-label="Permalink to &quot;🎒 開始前的準備&quot;">​</a></h2><ul><li>你已經能開啟 Antigravity Tools，並至少有一個帳號在帳號池裡</li><li>你知道帳號資料屬於敏感資訊（尤其是 <code>refresh_token</code>）</li></ul><div class="warning custom-block"><p class="custom-block-title">安全提醒：把備份檔案當作密碼</p><p>匯出的 JSON 檔案包含 <code>refresh_token</code>。任何拿到它的人，都可能用它去刷新 access token。不要把備份檔案上傳到網路硬碟公開連結、不要發群組、不要提交到 Git。</p></div><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>Antigravity Tools 的「遷移」本質上就兩件事：</p><ol><li>找到可用的 <code>refresh_token</code></li><li>用它換取 access token，並向 Google 取得真實信箱，然後把帳號寫進本機帳號池</li></ol><p>它提供了三個入口：</p><ul><li>JSON 匯入/匯出：適合你明確要做「可控備份」</li><li>DB 匯入：適合你把 Antigravity/IDE 的登入狀態當作權威來源（預設找 <code>state.vscdb</code>，也支援手選檔案）</li><li>V1 匯入：適合從舊資料目錄自動掃描並遷移</li></ul><p>另外還有一條「自動同步」：它會週期性讀取 DB 裡的 refresh_token，如果與 Manager 目前帳號不同，就自動執行一次 DB 匯入；如果相同就直接跳過（節省流量）。</p><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-匯出帳號池-json-備份" tabindex="-1">第 1 步：匯出帳號池（JSON 備份） <a class="header-anchor" href="#第-1-步-匯出帳號池-json-備份" aria-label="Permalink to &quot;第 1 步：匯出帳號池（JSON 備份）&quot;">​</a></h3><p><strong>為什麼</strong> 這是最穩定、最可控的遷移方式。你拿到一個檔案，就能在另一台機器恢復帳號池。</p><p>操作：進入 <code>Accounts</code> 頁面，點擊匯出按鈕。</p><ul><li>如果你在設定裡設定了 <code>default_export_path</code>，匯出會直接寫入該目錄，並使用檔名 <code>antigravity_accounts_YYYY-MM-DD.json</code>。</li><li>如果沒設定預設目錄，會彈出系統儲存對話方塊讓你選擇路徑。</li></ul><p>匯出檔案內容大致長這樣（陣列裡每項只保留必要欄位）：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;alice@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//xxxxxxxxxxxxxxxxxxxxxxxx&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bob@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//yyyyyyyyyyyyyyyyyyyyyyyy&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>你應該看到</strong>：頁面提示匯出成功，並顯示儲存路徑。</p><h3 id="第-2-步-在新機器匯入-json-恢復帳號池" tabindex="-1">第 2 步：在新機器匯入 JSON（恢復帳號池） <a class="header-anchor" href="#第-2-步-在新機器匯入-json-恢復帳號池" aria-label="Permalink to &quot;第 2 步：在新機器匯入 JSON（恢復帳號池）&quot;">​</a></h3><p><strong>為什麼</strong> 匯入會逐個呼叫「新增帳號」邏輯，用 <code>refresh_token</code> 拉取真實信箱並寫入帳號池。</p><p>操作：還是在 <code>Accounts</code> 頁面，點擊「匯入 JSON」，選擇你剛匯出的檔案。</p><p>格式要求如下（至少需包含 1 條有效記錄）：</p><ul><li>必須是 JSON 陣列</li><li>系統只會匯入包含 <code>refresh_token</code> 且以 <code>1//</code> 開頭的條目</li></ul><p><strong>你應該看到</strong>：匯入結束後，帳號列表裡出現匯入的帳號。</p><div class="tip custom-block"><p class="custom-block-title">如果你匯入時 Proxy 正在執行</p><p>每次「新增帳號」成功後，後端會嘗試 reload 反代的 token pool，讓新帳號立刻生效。</p></div><h3 id="第-3-步-從-state-vscdb-匯入「目前登入帳號」" tabindex="-1">第 3 步：從 <code>state.vscdb</code> 匯入「目前登入帳號」 <a class="header-anchor" href="#第-3-步-從-state-vscdb-匯入「目前登入帳號」" aria-label="Permalink to &quot;第 3 步：從 \`state.vscdb\` 匯入「目前登入帳號」&quot;">​</a></h3><p><strong>為什麼</strong> 有時候你不想維護備份檔案，只想「以 Antigravity/IDE 的登入狀態為準」。DB 匯入就是為這個場景準備的。</p><p>操作：進入 <code>Accounts</code> 頁面，點擊 <strong>Add Account</strong>，切到 <code>Import</code> 標籤頁：</p><ul><li>點「從資料庫匯入」（使用預設 DB 路徑）</li><li>或點「Custom DB (state.vscdb)」手動選擇一個 <code>*.vscdb</code> 檔案</li></ul><p>預設 DB 路徑是跨平台的（也會優先識別 <code>--user-data-dir</code> 或 portable mode）：</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-TkpuW" id="tab-zzOqN42" checked><label data-title="macOS" for="tab-zzOqN42">macOS</label><input type="radio" name="group-TkpuW" id="tab-ixlOlwA"><label data-title="Windows" for="tab-ixlOlwA">Windows</label><input type="radio" name="group-TkpuW" id="tab-3pXxt_4"><label data-title="Linux" for="tab-3pXxt_4">Linux</label></div><div class="blocks"><div class="language-text vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Application Support/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%APPDATA%\\Antigravity\\User\\globalStorage\\state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.config/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div></div></div><p><strong>你應該看到</strong>：</p><ul><li>匯入成功後，這個帳號會被自動設為 Manager 的「目前帳號」</li><li>系統會自動觸發一次配額刷新</li></ul><h3 id="第-4-步-從-v1-資料目錄遷移-舊版本匯入" tabindex="-1">第 4 步：從 V1 資料目錄遷移（舊版本匯入） <a class="header-anchor" href="#第-4-步-從-v1-資料目錄遷移-舊版本匯入" aria-label="Permalink to &quot;第 4 步：從 V1 資料目錄遷移（舊版本匯入）&quot;">​</a></h3><p><strong>為什麼</strong> 如果你以前用過 V1/腳本版，Manager 允許你直接掃描舊資料目錄並嘗試匯入。</p><p>操作：在 <code>Import</code> 標籤頁，點擊「匯入 V1」。</p><p>它會去你的 home 目錄下找這個路徑（以及其中的索引檔案）：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.antigravity-agent/</span></span>
<span class="line"><span>  - antigravity_accounts.json</span></span>
<span class="line"><span>  - accounts.json</span></span></code></pre></div><p><strong>你應該看到</strong>：匯入完成後，帳號出現在列表裡；如果沒找到索引檔案，後端會傳回錯誤 <code>V1 account data file not found</code>。</p><h3 id="第-5-步-可選-開啟「自動同步目前帳號」" tabindex="-1">第 5 步（可選）：開啟「自動同步目前帳號」 <a class="header-anchor" href="#第-5-步-可選-開啟「自動同步目前帳號」" aria-label="Permalink to &quot;第 5 步（可選）：開啟「自動同步目前帳號」&quot;">​</a></h3><p><strong>為什麼</strong> 當你在 Antigravity/IDE 裡切換登入帳號時，Manager 可以按固定間隔偵測 DB 中的 refresh_token 是否變化，並在變化時自動匯入。</p><p>操作：進入 <code>Settings</code>，開啟 <code>auto_sync</code>，並設定 <code>sync_interval</code>（單位：秒）。</p><p><strong>你應該看到</strong>：開啟後會立即執行一次同步；之後按間隔週期性執行。如果 DB 裡的 refresh_token 與目前帳號相同，會直接跳過，不會重複匯入。</p><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><ul><li>你能在 <code>Accounts</code> 列表中看到匯入的帳號</li><li>你能看見「目前帳號」已經切換到你期望的那一個（DB 匯入會自動設為目前）</li><li>你把 Proxy 啟動後，新匯入的帳號能被正常用於請求（以實際呼叫結果為準）</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><table tabindex="0"><thead><tr><th>場景</th><th>你可能會怎麼做（❌）</th><th>推薦做法（✓）</th></tr></thead><tbody><tr><td>備份檔案安全</td><td>把匯出的 JSON 當普通設定檔隨手發出去</td><td>把 JSON 當密碼，最小化傳播範圍，避免公網暴露</td></tr><tr><td>JSON 匯入失敗</td><td>JSON 不是陣列，或 refresh_token 沒有 <code>1//</code> 前綴</td><td>用本專案匯出的 JSON 作為範本，保持欄位名與結構一致</td></tr><tr><td>DB 匯入找不到資料</td><td>Antigravity 沒有登入過，或 DB 裡缺少 <code>jetskiStateSync.agentManagerInitState</code></td><td>先確認 Antigravity/IDE 已登入，再嘗試匯入；必要時用 Custom DB 選對檔案</td></tr><tr><td>V1 匯入後帳號不可用</td><td>舊 refresh_token 失效</td><td>刪除該帳號後用 OAuth/新 refresh_token 重新新增（以錯誤提示為準）</td></tr><tr><td>auto_sync 太頻繁</td><td><code>sync_interval</code> 設得很小，頻繁掃描 DB</td><td>把它當作「狀態跟隨」，間隔設到你能接受的頻率即可</td></tr></tbody></table><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><ul><li>JSON 匯出/匯入是最可控的遷移方式：備份檔案裡只保留 <code>email + refresh_token</code></li><li>DB 匯入適合「以 Antigravity/IDE 目前登入帳號為準」，並會自動設為 Manager 目前帳號</li><li>V1 匯入會掃描 <code>~/.antigravity-agent</code> 並相容多種舊格式</li><li>auto_sync 會比較 refresh_token；相同則跳過，不會重複匯入</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們把「遷移後的帳號池」真正用起來：<strong><a href="./../proxy-and-first-client/">啟動本機反代並接入第一個客戶端（/healthz + SDK 設定）</a></strong>。</p><p>你會學到：</p><ul><li>怎麼啟動/停止 Proxy，並用 <code>/healthz</code> 做最小驗證</li><li>怎麼在 SDK/客戶端裡設定 Base URL</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>Accounts 匯出/匯入 JSON（<code>save_text_file</code> / <code>read_text_file</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L458-L578" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>458-578</td></tr><tr><td>Dashboard 匯出帳號 JSON</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Dashboard.tsx#L113-L148" target="_blank" rel="noreferrer"><code>src/pages/Dashboard.tsx</code></a></td><td>113-148</td></tr><tr><td>Import 標籤頁：DB 匯入 / Custom DB / V1 匯入按鈕</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L491-L539" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>491-539</td></tr><tr><td>新增帳號：忽略前端 email、用 refresh_token 取得真實信箱、自動刷新配額、Proxy 熱 reload</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L19-L60" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>19-60</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>DB 匯入：從 <code>state.vscdb</code> 提取 refresh_token（ItemTable + base64 + protobuf）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/migration.rs#L192-L267" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/migration.rs</code></a></td><td>192-267</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>DB 匯入後自動設為「目前帳號」並刷新配額</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L495-L511" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>495-511</td></tr><tr><td>auto_sync：比較 refresh_token，相同直接跳過；變化則觸發 DB 匯入</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L532-L564" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>532-564</td></tr><tr><td>前端背景工作：按 <code>sync_interval</code> 週期性呼叫 <code>syncAccountFromDb()</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/common/BackgroundTaskRunner.tsx#L43-L72" target="_blank" rel="noreferrer"><code>src/components/common/BackgroundTaskRunner.tsx</code></a></td><td>43-72</td></tr></tbody></table></details>`,61)])])}const g=a(r,[["render",o]]);export{u as __pageData,g as default};
